303→const parseMediaTimestamp = (item = {}) => {
304→    const fileName = item?.name || '';
305→    const timestampPrefix = fileName.match(/^(\d+)_/);
306→
307→    if(timestampPrefix?.[1]){
308→        const parsedPrefix = Number(timestampPrefix[1]);
309→        if(!Number.isNaN(parsedPrefix)){
310→            return parsedPrefix;
311→        }
312→    }
313→
314→    const parsedDate = Date.parse(item?.created_at || item?.updated_at || '');
315→    return Number.isNaN(parsedDate) ? 0 : parsedDate;
316→};
